def validate_resolved_intent(rint, known_iec_refs, known_request_refs):
    problems = []

    # R6: Check if rint is a dict
    if not isinstance(rint, dict):
        return {"ok": False, "problems": ["rint is not a dict"]}

    # Required fields
    required_fields = ["resolved_intent_id", "request_id", "primary_intent", "intent_status", "strategy", "iec_ref"]

    # R1: Check all required fields present
    missing_fields = [f for f in required_fields if f not in rint]
    if missing_fields:
        return {"ok": False, "problems": [f"Missing required fields: {missing_fields}"]}

    # R6: Check types of required fields (all should be str except retained_intent_branches which is optional)
    for field in required_fields:
        if not isinstance(rint[field], str):
            return {"ok": False, "problems": [f"Field '{field}' has wrong type (expected str)"]}

    # Check optional retained_intent_branches if present
    if "retained_intent_branches" in rint:
        if not isinstance(rint["retained_intent_branches"], list):
            return {"ok": False, "problems": ["retained_intent_branches must be a list or not present"]}

    # R2: intent_status must be one of the 6 values
    valid_intent_statuses = ["RESOLVED", "RESOLVED_WITH_RESIDUAL", "MULTI_INTENT", "CLARIFICATION_REQUIRED", "PREMISE_UNRESOLVED", "DEFERRED"]
    if rint["intent_status"] not in valid_intent_statuses:
        return {"ok": False, "problems": [f"intent_status '{rint['intent_status']}' is not valid"]}

    # R3: strategy must be one of the 7 values
    valid_strategies = ["DIRECT", "CONTEXT_RESOLVE", "CHOICE", "BOUNDED_MULTI_VIEW", "INTENT_PROBE", "PREMISE_PROBE", "DEFER"]
    if rint["strategy"] not in valid_strategies:
        return {"ok": False, "problems": [f"strategy '{rint['strategy']}' is not valid"]}

    # R4: iec_ref must be in known_iec_refs
    if rint["iec_ref"] not in known_iec_refs:
        return {"ok": False, "problems": [f"iec_ref '{rint['iec_ref']}' is not in known_iec_refs (FABRICATION)"]}

    # R5: request_id must be in known_request_refs
    if rint["request_id"] not in known_request_refs:
        return {"ok": False, "problems": [f"request_id '{rint['request_id']}' is not in known_request_refs"]}

    # R7: Check retained_intent_branches for residual/multi-intent cases
    if rint["intent_status"] in ["RESOLVED_WITH_RESIDUAL", "MULTI_INTENT"]:
        retained = rint.get("retained_intent_branches")
        if retained is None or not isinstance(retained, list) or len(retained) == 0:
            return {"ok": False, "problems": [f"intent_status '{rint['intent_status']}' requires non-empty retained_intent_branches"]}

    return {"ok": True, "problems": []}
